/**
 * @vitest-environment jsdom
 */
/**
 * Unit tests: App.tsx plugin + layout engine integration (Step 05-03)
 *
 * Validates that App.tsx:
 * 1. Initializes the plugin system (loads norbert-session plugin)
 * 2. Renders the ZoneRenderer instead of hardcoded views
 * 3. Builds a view registry mapping viewIds to React components
 * 4. Keeps MenuBar and status bar footer
 * 5. Session list functionality remains accessible through the layout engine
 */

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { render, screen, waitFor, cleanup } from "@testing-library/react";
import "@testing-library/jest-dom/vitest";
import React from "react";
import { invoke } from "@tauri-apps/api/core";

// Mock @tauri-apps/api/core before importing App
vi.mock("@tauri-apps/api/core", () => ({
  invoke: vi.fn(),
}));

const mockedInvoke = vi.mocked(invoke);

// Must import App after mock setup
import App from "../../src/App";

function setupDefaultMocks() {
  mockedInvoke.mockImplementation((cmd: string) => {
    if (cmd === "get_status") {
      return Promise.resolve({
        version: "0.2.1-test",
        port: 3001,
        session_count: 2,
        event_count: 10,
      });
    }
    if (cmd === "get_sessions") {
      return Promise.resolve([
        {
          id: "session-1",
          started_at: "2026-03-12T10:00:00Z",
          last_event_at: "2026-03-12T10:05:00Z",
          event_count: 5,
        },
        {
          id: "session-2",
          started_at: "2026-03-12T09:00:00Z",
          last_event_at: "2026-03-12T09:30:00Z",
          event_count: 5,
        },
      ]);
    }
    return Promise.reject(new Error(`Unknown command: ${cmd}`));
  });
}

afterEach(() => {
  cleanup();
});

beforeEach(() => {
  vi.clearAllMocks();
  setupDefaultMocks();

  const store: Record<string, string> = {};
  vi.stubGlobal("localStorage", {
    getItem: (key: string) => store[key] ?? null,
    setItem: (key: string, value: string) => { store[key] = value; },
    removeItem: (key: string) => { delete store[key]; },
    clear: () => Object.keys(store).forEach((k) => delete store[k]),
    get length() { return Object.keys(store).length; },
    key: (i: number) => Object.keys(store)[i] ?? null,
  });
});

// ---------------------------------------------------------------------------
// App renders through layout engine, not hardcoded views
// ---------------------------------------------------------------------------

describe("App renders via plugin system and layout engine", () => {
  it("renders the ZoneRenderer container instead of hardcoded views", async () => {
    const { container } = render(<App />);

    await waitFor(() => {
      expect(screen.getByText("View")).toBeInTheDocument();
    });

    // ZoneRenderer renders a zone-container div
    const zoneContainer = container.querySelector("[data-testid='zone-container']");
    expect(zoneContainer).toBeInTheDocument();
  });

  it("renders session list inside the main zone via view registry", async () => {
    const { container } = render(<App />);

    await waitFor(() => {
      // Session rows should still be rendered (via the plugin view registry)
      const zoneMain = container.querySelector("[data-testid='zone-main']");
      expect(zoneMain).toBeInTheDocument();
    });
  });

  it("preserves the MenuBar with View entry", async () => {
    render(<App />);

    await waitFor(() => {
      expect(screen.getByText("View")).toBeInTheDocument();
    });
  });

  it("preserves the status bar footer with live metrics", async () => {
    render(<App />);

    await waitFor(() => {
      expect(screen.getByText(/Status:/)).toBeInTheDocument();
    });

    expect(screen.getByText(/Port: \d+/)).toBeInTheDocument();
    expect(screen.getByText(/Sessions: \d+/)).toBeInTheDocument();
    expect(screen.getByText(/Events: \d+/)).toBeInTheDocument();
  });
});

// ---------------------------------------------------------------------------
// App.tsx delegates view rendering to Layout Engine (no inline view JSX)
// ---------------------------------------------------------------------------

describe("App.tsx delegates view rendering to Layout Engine", () => {
  it("does not render SessionListView or EventDetailView directly in JSX", async () => {
    const fs = await import("fs");
    const appSource = fs.readFileSync("src/App.tsx", "utf-8");

    // App.tsx should NOT have <SessionListView or <EventDetailView in its JSX return.
    // These views are rendered through the ZoneRenderer via the view registry.
    // The regex matches JSX usage like <SessionListView or <EventDetailView
    // but NOT import statements or variable references.
    const jsxSessionList = appSource.match(/<SessionListView[\s/>]/);
    const jsxEventDetail = appSource.match(/<EventDetailView[\s/>]/);

    // Only wrapper/factory definitions are allowed (inside useMemo etc.)
    // The main JSX return of App should use <ZoneRenderer instead
    expect(appSource).toContain("<ZoneRenderer");

    // The JSX in the return statement should not directly render view components
    // We verify this by checking that the return JSX block uses ZoneRenderer
    const returnBlock = appSource.slice(appSource.lastIndexOf("return ("));
    expect(returnBlock).toContain("ZoneRenderer");
    expect(returnBlock).not.toContain("<SessionListView");
    expect(returnBlock).not.toContain("<EventDetailView");
  });
});

tests/acceptance/norbert-performance-mon.source:
/**
 * Acceptance tests: Per-Session Per-Category Time-Series Buffers (v2)
 *
 * Validates the MultiSessionStore extension: per-session per-category
 * ring buffers, aggregate buffer computation, subscriber notification,
 * and the aggregate applicability rule (context has no aggregate).
 *
 * Driving ports: extended MultiSessionStore adapter
 * These tests exercise the adapter boundary with real internal domain
 * functions (ring buffers), mocking nothing internal.
 *
 * Traces to: ADR-008 "Per-Session Per-Category Time-Series Buffers",
 * ADR-009 "Aggregate Applicability by Category",
 * architecture-design.md "MultiSessionStore Extension",
 * data-models.md "Extended MultiSessionStore Interface"
 */

import { describe, it, expect } from "vitest";

// Driving port: extended MultiSessionStore (adapter boundary)
// These imports will resolve once the module is extended.
import {
  createMultiSessionStore,
  type MultiSessionStore,
  type CategorySampleInput,
} from "../../../src/plugins/norbert-usage/adapters/multiSessionStore";

import type { MetricCategoryId } from "../../../src/plugins/norbert-usage/domain/categoryConfig";

// Hook processor: driving port for the category sample feeding pipeline
import { createHookProcessor, type HookProcessorDeps } from "../../../src/plugins/norbert-usage/hookProcessor";
import type { SessionMetrics } from "../../../src/plugins/norbert-usage/domain/types";
import { createInitialMetrics } from "../../../src/plugins/norbert-usage/domain/metricsAggregator";
import { DEFAULT_PRICING_TABLE } from "../../../src/plugins/norbert-usage/domain/pricingModel";

// ---------------------------------------------------------------------------
// WALKING SKELETON: User sees per-session graphs update with new data
// Traces to: ADR-008, US-PM-002 per-session graphs
// ---------------------------------------------------------------------------

describe("User sees per-session metric graphs update as events arrive", () => {
  it("appending a sample to a session creates per-category time-series data", () => {
    // Given a multi-session store with one active session "refactor-auth"
    const store = createMultiSessionStore();
    store.addSession("refactor-auth");

    // When a category sample is appended for that session
    store.appendSessionSample("refactor-auth", {
      tokens: 312,
      cost: 0.003,
      agents: 2,
      context: 45,
    });

    // Then the session's token buffer contains the sample
    const tokenBuffer = store.getSessionBuffer("refactor-auth", "tokens");
    expect(tokenBuffer).toBeDefined();
    expect(tokenBuffer!.samples.length).toBeGreaterThan(0);

    // And the session's context buffer also contains the sample
    const contextBuffer = store.getSessionBuffer("refactor-auth", "context");
    expect(contextBuffer).toBeDefined();
    expect(contextBuffer!.samples.length).toBeGreaterThan(0);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Per-Session Buffer Operations
// Traces to: ADR-008, data-models.md PerSessionCategoryBuffers
// ---------------------------------------------------------------------------

describe("Each session maintains independent buffers per category", () => {
  it("two sessions have separate token buffers with different values", () => {
    // Given two active sessions with different token rates
    const store = createMultiSessionStore();
    store.addSession("session-a");
    store.addSession("session-b");

    // When different samples are appended to each session
    store.appendSessionSample("session-a", { tokens: 500, cost: 0.005, agents: 1, context: 30 });
    store.appendSessionSample("session-b", { tokens: 100, cost: 0.001, agents: 2, context: 60 });

    // Then session-a's token buffer has its own values
    const bufferA = store.getSessionBuffer("session-a", "tokens");
    // And session-b's token buffer has its own values
    const bufferB = store.getSessionBuffer("session-b", "tokens");

    expect(bufferA).toBeDefined();
    expect(bufferB).toBeDefined();
    // And the values are independent (not mixed)
    expect(bufferA!.samples).not.toEqual(bufferB!.samples);
  });
});

describe("Removing a session cleans up its per-category buffers", () => {
  it("removed session's buffers are no longer accessible", () => {
    // Given a session with buffered samples
    const store = createMultiSessionStore();
    store.addSession("temp-session");
    store.appendSessionSample("temp-session", { tokens: 200, cost: 0.002, agents: 1, context: 50 });

    // When the session is removed
    store.removeSession("temp-session");

    // Then the session's buffers return undefined
    const buffer = store.getSessionBuffer("temp-session", "tokens");
    expect(buffer).toBeUndefined();
  });
});

describe("Appending to a nonexistent session is a no-op", () => {
  it("no error when appending to unknown session ID", () => {
    // Given an empty store
    const store = createMultiSessionStore();

    // When a sample is appended to a session that does not exist
    // Then no error is thrown
    expect(() => {
      store.appendSessionSample("ghost-session", { tokens: 100, cost: 0, agents: 0, context: 0 });
    }).not.toThrow();

    // And no buffer is created for the unknown session
    const buffer = store.getSessionBuffer("ghost-session", "tokens");
    expect(buffer).toBeUndefined();
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Aggregate Buffer Computation
// Traces to: ADR-008 "aggregate ring buffers", ADR-009
// ---------------------------------------------------------------------------

describe("Aggregate token buffer sums across all sessions", () => {
  it("aggregate token value equals sum of per-session token rates", () => {
    // Given 3 sessions with known token rates
    const store = createMultiSessionStore();
    store.addSession("s1");
    store.addSession("s2");
    store.addSession("s3");

    store.appendSessionSample("s1", { tokens: 312, cost: 0.003, agents: 1, context: 45 });
    store.appendSessionSample("s2", { tokens: 185, cost: 0.002, agents: 2, context: 67 });
    store.appendSessionSample("s3", { tokens: 30, cost: 0.0003, agents: 1, context: 20 });

    // When the aggregate token buffer is read
    const aggBuffer = store.getAggregateBuffer("tokens");

    // Then the aggregate value is the sum (312 + 185 + 30 = 527)
    expect(aggBuffer).toBeDefined();
    const latestSample = aggBuffer!.samples[aggBuffer!.samples.length - 1];
    expect(latestSample).toBeDefined();
    // The aggregate sample value equals the sum: 312 + 185 + 30 = 527
    expect(latestSample.tokenRate).toBe(527);
  });
});

describe("Aggregate cost buffer sums across all sessions", () => {
  it("aggregate cost value equals sum of per-session cost rates", () => {
    // Given 2 sessions with known cost rates
    const store = createMultiSessionStore();
    store.addSession("opus-session");
    store.addSession("sonnet-session");

    store.appendSessionSample("opus-session", { tokens: 300, cost: 0.18, agents: 1, context: 40 });
    store.appendSessionSample("sonnet-session", { tokens: 100, cost: 0.004, agents: 1, context: 30 });

    // When the aggregate cost buffer is read
    const aggBuffer = store.getAggregateBuffer("cost");

    // Then the aggregate cost value equals the sum: 0.18 + 0.004 = 0.184
    // (category value stored in tokenRate field -- see multiSessionStore convention)
    expect(aggBuffer).toBeDefined();
    expect(aggBuffer!.samples.length).toBeGreaterThan(0);
    const latestSample = aggBuffer!.samples[aggBuffer!.samples.length - 1];
    expect(latestSample.tokenRate).toBeCloseTo(0.184);
  });
});

describe("Context category has no aggregate buffer", () => {
  it("aggregate context buffer is empty or not populated", () => {
    // Given multiple sessions with context data
    const store = createMultiSessionStore();
    store.addSession("s1");
    store.addSession("s2");

    store.appendSessionSample("s1", { tokens: 100, cost: 0.001, agents: 1, context: 45 });
    store.appendSessionSample("s2", { tokens: 200, cost: 0.002, agents: 1, context: 72 });

    // When the aggregate context buffer is requested
    const aggBuffer = store.getAggregateBuffer("context");

    // Then the buffer is empty (context aggregation is not applicable per ADR-009)
    expect(aggBuffer.samples).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Subscriber Notification
// Traces to: data-models.md "subscribe(callback)"
// ---------------------------------------------------------------------------

describe("Subscribers are notified when samples are appended", () => {
  it("callback invoked after appendSessionSample", () => {
    // Given a store with a subscriber
    const store = createMultiSessionStore();
    store.addSession("test-session");

    let notified = false;
    const unsubscribe = store.subscribe(() => { notified = true; });

    // When a sample is appended
    store.appendSessionSample("test-session", { tokens: 100, cost: 0, agents: 1, context: 50 });

    // Then the subscriber is notified
    expect(notified).toBe(true);

    // Cleanup
    unsubscribe();
  });
});

describe("Unsubscribed callbacks are not invoked", () => {
  it("callback not called after unsubscribe", () => {
    // Given a store with a subscriber that has been unsubscribed
    const store = createMultiSessionStore();
    store.addSession("test-session");

    let callCount = 0;
    const unsubscribe = store.subscribe(() => { callCount += 1; });
    unsubscribe();

    // When a sample is appended
    store.appendSessionSample("test-session", { tokens: 100, cost: 0, agents: 1, context: 50 });

    // Then the callback was not called
    expect(callCount).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Backward Compatibility
// Traces to: architecture-design.md "Backward Compatibility"
// ---------------------------------------------------------------------------

describe("Existing store operations unchanged after extension", () => {
  it("addSession, removeSession, updateSession, getSessions, getSession still work", () => {
    // Given the extended multi-session store
    const store = createMultiSessionStore();

    // When using the original v1 interface
    store.addSession("compat-test");
    const session = store.getSession("compat-test");

    // Then sessions are trackable via the original interface
    expect(session).toBeDefined();
    expect(session!.sessionId).toBe("compat-test");

    // And getSessions returns all tracked sessions
    const all = store.getSessions();
    expect(all).toHaveLength(1);
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIOS: Buffer Boundary Conditions
// ---------------------------------------------------------------------------

describe("Getting buffer for unknown category returns empty buffer", () => {
  it("unknown category ID returns empty or undefined buffer", () => {
    // Given a session with samples
    const store = createMultiSessionStore();
    store.addSession("test");
    store.appendSessionSample("test", { tokens: 100, cost: 0, agents: 1, context: 50 });

    // When requesting a buffer for an unknown category
    const buffer = store.getSessionBuffer("test", "nonexistent" as MetricCategoryId);

    // Then no buffer data is returned
    expect(buffer).toBeUndefined();
  });
});

describe("Adding same session twice is idempotent", () => {
  it("duplicate addSession does not reset existing buffers", () => {
    // Given a session with existing sample data
    const store = createMultiSessionStore();
    store.addSession("dup-test");
    store.appendSessionSample("dup-test", { tokens: 500, cost: 0.005, agents: 2, context: 60 });

    // When addSession is called again with the same ID
    store.addSession("dup-test");

    // Then the existing buffer data is preserved (not reset)
    const buffer = store.getSessionBuffer("dup-test", "tokens");
    expect(buffer).toBeDefined();
    expect(buffer!.samples.length).toBeGreaterThan(0);
  });
});

describe("Aggregate buffer updates when a session is removed", () => {
  it("aggregate recalculates after session removal", () => {
    // Given 2 sessions contributing to aggregate
    const store = createMultiSessionStore();
    store.addSession("keep");
    store.addSession("remove");
    store.appendSessionSample("keep", { tokens: 300, cost: 0.003, agents: 1, context: 40 });
    store.appendSessionSample("remove", { tokens: 200, cost: 0.002, agents: 1, context: 50 });

    // When one session is removed
    store.removeSession("remove");

    // Then the aggregate buffer no longer includes the removed session's data
    // (next append to remaining session should produce correct aggregate)
    store.appendSessionSample("keep", { tokens: 350, cost: 0.003, agents: 1, context: 42 });
    const aggBuffer = store.getAggregateBuffer("tokens");
    expect(aggBuffer).toBeDefined();
  });
});

describe("Multiple rapid samples accumulate in ring buffer", () => {
  it("consecutive appends increase buffer sample count", () => {
    // Given a session receiving rapid event updates
    const store = createMultiSessionStore();
    store.addSession("rapid");

    // When 5 samples are appended
    for (let i = 0; i < 5; i++) {
      store.appendSessionSample("rapid", { tokens: 100 + i * 10, cost: 0.001, agents: 1, context: 40 });
    }

    // Then the buffer contains the samples
    const buffer = store.getSessionBuffer("rapid", "tokens");
    expect(buffer).toBeDefined();
    expect(buffer!.samples.length).toBe(5);
  });
});

// ---------------------------------------------------------------------------
// PROPERTY-SHAPED SCENARIOS
// Traces to: ADR-009 -- context never aggregated
// ---------------------------------------------------------------------------

describe("@property: context aggregate buffer is never populated regardless of session count", () => {
  it("for any number of sessions, context aggregate remains empty", () => {
    // Given varying numbers of sessions (1 through 5)
    const store = createMultiSessionStore();
    for (let i = 1; i <= 5; i++) {
      store.addSession(`session-${i}`);
      store.appendSessionSample(`session-${i}`, {
        tokens: 100 * i,
        cost: 0.001 * i,
        agents: i,
        context: 20 * i,
      });

      // When the context aggregate buffer is checked after each addition
      const aggBuffer = store.getAggregateBuffer("context");

      // Then the context aggregate buffer is always empty
      expect(aggBuffer.samples).toHaveLength(0);
    }
  });
});

describe("@property: aggregate sum always equals sum of per-session latest values", () => {
  it("tokens aggregate latest value equals sum of per-session latest values", () => {
    // Given 3 sessions with known token rates
    const store = createMultiSessionStore();
    const rates = [312, 185, 30];
    for (let i = 0; i < rates.length; i++) {
      store.addSession(`s${i}`);
      store.appendSessionSample(`s${i}`, { tokens: rates[i], cost: 0, agents: 1, context: 0 });
    }

    // When the aggregate tokens buffer is read
    const aggBuffer = store.getAggregateBuffer("tokens");

    // Then the aggregate sum invariant holds: aggregate equals sum of per-session latest values
    expect(aggBuffer).toBeDefined();
    expect(aggBuffer!.samples.length).toBeGreaterThan(0);
    const expectedSum = rates.reduce((sum, r) => sum + r, 0);
    expect(aggBuffer!.samples[aggBuffer!.samples.length - 1].tokenRate).toBe(expectedSum);
  });
});

// ---------------------------------------------------------------------------
// STEP 02-02: Hook processor feeds category samples to MultiSessionStore
// Traces to: architecture-design.md "hookProcessor -> appendSessionSample"
// ---------------------------------------------------------------------------

describe("Hook processor feeds per-category samples after metrics update", () => {
  // Helper: create a hook processor with spy appendSessionSample
  const createTestProcessor = () => {
    // Mutable session metrics store (spy for updateMultiSessionMetrics)
    const sessionMetrics = new Map<string, SessionMetrics>();
    const appendedSamples: Array<{ sessionId: string; samples: CategorySampleInput }> = [];

    const deps: HookProcessorDeps = {
      updateMetrics: () => {}, // single-session pipeline -- no-op for these tests
      updateMultiSessionMetrics: (sessionId, _label, reducer) => {
        const prev = sessionMetrics.get(sessionId) ?? createInitialMetrics(sessionId);
        sessionMetrics.set(sessionId, reducer(prev));
      },
      appendSessionSample: (sessionId, samples) => {
        appendedSamples.push({ sessionId, samples });
      },
      pricingTable: DEFAULT_PRICING_TABLE,
    };

    const processor = createHookProcessor(deps);
    return { processor, appendedSamples, sessionMetrics };
  };

  it("Token rate sample derived from instantaneous rate on event", () => {
    // Given a hook processor wired with appendSessionSample spy
    const { processor, appendedSamples } = createTestProcessor();

    // When a prompt_submit event arrives with token usage for session "s1"
    // First event establishes baseline
    processor({
      session_id: "s1",
      event_type: "prompt_submit",
      payload: {
        usage: { input_tokens: 100, output_tokens: 50, cache_read_tokens: 0, cache_creation_tokens: 0 },
        model: "claude-sonnet-4-20250514",
      },
    });

    // Then appendSessionSample was called with the session ID and a tokens value
    expect(appendedSamples.length).toBeGreaterThanOrEqual(1);
    const lastSample = appendedSamples[appendedSamples.length - 1];
    expect(lastSample.sessionId).toBe("s1");
    // Token rate is derived from instantaneous rate computation (>= 0)
    expect(lastSample.samples.tokens).toBeGreaterThanOrEqual(0);
    expect(typeof lastSample.samples.tokens).toBe("number");
    // Cost rate is also derived from instantaneous rate (>= 0)
    expect(lastSample.samples.cost).toBeGreaterThanOrEqual(0);
    expect(typeof lastSample.samples.cost).toBe("number");
  });

  it("Agent count sample derived from session metrics", () => {
    // Given a hook processor wired with appendSessionSample spy
    const { processor, appendedSamples } = createTestProcessor();

    // When a session_start event arrives (increments activeAgentCount)
    processor({
      session_id: "s2",
      event_type: "session_start",
      payload: {},
    });

    // Then appendSessionSample was called with agents value from updated metrics
    expect(appendedSamples.length).toBeGreaterThanOrEqual(1);
    const lastSample = appendedSamples[appendedSamples.length - 1];
    expect(lastSample.sessionId).toBe("s2");
    // Agent count should be 1 after session_start
    expect(lastSample.samples.agents).toBe(1);
    // Context percentage should also be present (from metrics)
    expect(typeof lastSample.samples.context).toBe("number");
  });

  it("Existing single-session pipeline unchanged after extension", () => {
    // Given a hook processor with both single-session and multi-session callbacks
    let singleSessionUpdated = false;
    const deps: HookProcessorDeps = {
      updateMetrics: () => { singleSessionUpdated = true; },
      updateMultiSessionMetrics: (_sid, _reducer) => {},
      appendSessionSample: (_sid, _samples) => {},
      pricingTable: DEFAULT_PRICING_TABLE,
    };
    const processor = createHookProcessor(deps);

    // When an event arrives
    processor({
      session_id: "s3",
      event_type: "prompt_submit",
      payload: {
        usage: { input_tokens: 50, output_tokens: 25, cache_read_tokens: 0, cache_creation_tokens: 0 },
        model: "claude-sonnet-4-20250514",
      },
    });

    // Then the single-session updateMetrics callback was still invoked
    expect(singleSessionUpdated).toBe(true);
  });
});

tests/acceptance/pm-chart-reliability/ch.source:
/**
 * Acceptance tests: Chart Data Rendering (pm-chart-reliability)
 *
 * Validates that the Performance Monitor charts display visible, non-empty
 * data whenever active sessions are generating events. Covers the data
 * pipeline from sample append through buffer retrieval to coordinate
 * computation for canvas rendering.
 *
 * Driving ports:
 *   - multiSessionStore (adapter boundary)
 *   - chartRenderer.prepareFilledAreaPoints (domain)
 *   - chartRenderer.prepareSparklinePoints (domain)
 *
 * Traces to: US-PMR-01 acceptance criteria
 */

import { describe, it, expect } from "vitest";

import {
  createMultiSessionStore,
  type MultiSessionStore,
} from "../../../src/plugins/norbert-usage/adapters/multiSessionStore";

import {
  prepareFilledAreaPoints,
  prepareSparklinePoints,
  type FilledAreaPoint,
} from "../../../src/plugins/norbert-usage/domain/chartRenderer";

import type { CanvasDimensions } from "../../../src/plugins/norbert-usage/domain/oscilloscope";

// ---------------------------------------------------------------------------
// Fixtures
// ---------------------------------------------------------------------------

const CHART_DIMENSIONS: CanvasDimensions = {
  width: 400,
  height: 200,
  padding: 10,
};

const SPARKLINE_DIMENSIONS: CanvasDimensions = {
  width: 80,
  height: 20,
  padding: 0,
};

/** Populate a store with a session and append N samples at a given rate. */
const populateSession = (
  store: MultiSessionStore,
  sessionId: string,
  tokenRate: number,
  sampleCount: number,
): void => {
  store.addSession(sessionId);
  for (let i = 0; i < sampleCount; i++) {
    store.appendSessionSample(sessionId, {
      tokens: tokenRate,
      cost: tokenRate * 0.001,
      agents: 1,
      context: 40,
    });
  }
};

/** Convert buffer samples to chart-compatible format. */
const toChartSamples = (
  samples: ReadonlyArray<{ timestamp: number; tokenRate: number }>,
): ReadonlyArray<{ timestamp: number; value: number }> =>
  samples.map((s) => ({ timestamp: s.timestamp, value: s.tokenRate }));

// ---------------------------------------------------------------------------
// WALKING SKELETON: Raj sees chart data for active sessions
// Traces to: US-PMR-01 AC1, AC2
// ---------------------------------------------------------------------------

describe("Raj sees a visible chart line when sessions are generating data", () => {
  it("aggregate chart has renderable points when 3 sessions are active", () => {
    // Given Raj has 3 active Claude Code sessions generating token events
    const store = createMultiSessionStore();
    populateSession(store, "refactor-abc1", 420, 15);
    populateSession(store, "tests-def2", 310, 15);
    populateSession(store, "chat-ghi3", 110, 15);

    // When the aggregate token buffer is retrieved and mapped to chart points
    const aggBuffer = store.getAggregateBuffer("tokens");
    const chartSamples = toChartSamples(aggBuffer.samples);
    const points = prepareFilledAreaPoints(chartSamples, CHART_DIMENSIONS, 1000);

    // Then the chart has at least 10 visible data points
    expect(points.length).toBeGreaterThanOrEqual(10);

    // And all points have finite canvas coordinates (no NaN, no blank chart)
    for (const point of points) {
      expect(Number.isFinite(point.x)).toBe(true);
      expect(Number.isFinite(point.y)).toBe(true);
    }

    // And at least one point is above the baseline (non-zero data visible)
    const bottomY = CHART_DIMENSIONS.height - CHART_DIMENSIONS.padding;
    const hasVisibleData = points.some((p) => p.y < bottomY);
    expect(hasVisibleData).toBe(true);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Aggregate buffer content
// Traces to: US-PMR-01 AC1
// ---------------------------------------------------------------------------

describe("Aggregate chart reflects combined token rate across sessions", () => {
  it("aggregate buffer latest value equals sum of per-session rates", () => {
    // Given 3 sessions with known token rates: 420, 310, 110
    const store = createMultiSessionStore();
    store.addSession("s1");
    store.addSession("s2");
    store.addSession("s3");
    store.appendSessionSample("s1", { tokens: 420, cost: 0.42, agents: 1, context: 30 });
    store.appendSessionSample("s2", { tokens: 310, cost: 0.31, agents: 1, context: 50 });
    store.appendSessionSample("s3", { tokens: 110, cost: 0.11, agents: 1, context: 25 });

    // When the aggregate token buffer is read
    const aggBuffer = store.getAggregateBuffer("tokens");
    const latestSample = aggBuffer.samples[aggBuffer.samples.length - 1];

    // Then the aggregate value is 840 (420 + 310 + 110)
    expect(latestSample.tokenRate).toBe(840);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Per-session mini charts
// Traces to: US-PMR-01 AC3
// ---------------------------------------------------------------------------

describe("Per-session mini charts show individual session data", () => {
  it("each session buffer produces sparkline points with non-zero amplitude", () => {
    // Given 3 sessions with rates 420, 310, 110
    const store = createMultiSessionStore();
    populateSession(store, "refactor-abc1", 420, 10);
    populateSession(store, "tests-def2", 310, 10);
    populateSession(store, "chat-ghi3", 110, 10);

    // When sparkline points are prepared for each session
    const sessions = ["refactor-abc1", "tests-def2", "chat-ghi3"];
    for (const sessionId of sessions) {
      const buffer = store.getSessionBuffer(sessionId, "tokens");
      expect(buffer).toBeDefined();
      const chartSamples = toChartSamples(buffer!.samples);
      const points = prepareSparklinePoints(chartSamples, SPARKLINE_DIMENSIONS, 500);

      // Then each session has renderable sparkline points
      expect(points.length).toBeGreaterThan(0);
    }
  });

  it("higher-rate session produces higher amplitude sparkline than lower-rate session", () => {
    // Given refactor-abc1 at 420 tok/s and chat-ghi3 at 110 tok/s
    const store = createMultiSessionStore();
    populateSession(store, "refactor-abc1", 420, 10);
    populateSession(store, "chat-ghi3", 110, 10);

    // When sparkline points are prepared with the same yMax
    const yMax = 500;
    const bufferHigh = store.getSessionBuffer("refactor-abc1", "tokens")!;
    const bufferLow = store.getSessionBuffer("chat-ghi3", "tokens")!;
    const pointsHigh = prepareSparklinePoints(toChartSamples(bufferHigh.samples), SPARKLINE_DIMENSIONS, yMax);
    const pointsLow = prepareSparklinePoints(toChartSamples(bufferLow.samples), SPARKLINE_DIMENSIONS, yMax);

    // Then the high-rate session has lower Y values (higher on canvas = lower Y)
    const avgYHigh = pointsHigh.reduce((sum, p) => sum + p.y, 0) / pointsHigh.length;
    const avgYLow = pointsLow.reduce((sum, p) => sum + p.y, 0) / pointsLow.length;
    expect(avgYHigh).toBeLessThan(avgYLow);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Chart line advances over time
// Traces to: US-PMR-01 AC2
// ---------------------------------------------------------------------------

describe("Chart line extends rightward as new samples arrive", () => {
  it("appending samples increases the number of chart points", () => {
    // Given a session with 5 initial samples
    const store = createMultiSessionStore();
    populateSession(store, "advancing", 300, 5);
    const initialBuffer = store.getAggregateBuffer("tokens");
    const initialPointCount = initialBuffer.samples.length;

    // When 5 more seconds of events arrive
    for (let i = 0; i < 5; i++) {
      store.appendSessionSample("advancing", { tokens: 300, cost: 0.3, agents: 1, context: 40 });
    }

    // Then the buffer has grown with new data points
    const updatedBuffer = store.getAggregateBuffer("tokens");
    expect(updatedBuffer.samples.length).toBeGreaterThan(initialPointCount);

    // And the rightmost point has a more recent timestamp
    const lastInitial = initialBuffer.samples[initialBuffer.samples.length - 1];
    const lastUpdated = updatedBuffer.samples[updatedBuffer.samples.length - 1];
    expect(lastUpdated.timestamp).toBeGreaterThanOrEqual(lastInitial.timestamp);
  });
});

// ---------------------------------------------------------------------------
// FOCUSED SCENARIOS: Session lifecycle
// Traces to: US-PMR-01 AC5
// ---------------------------------------------------------------------------

describe("Chart continues after a session ends", () => {
  it("removing a session leaves remaining sessions contributing to aggregate", () => {
    // Given 3 active sessions contributing to aggregate
    const store = createMultiSessionStore();
    populateSession(store, "keep-a", 420, 5);
    populateSession(store, "keep-b", 310, 5);
    populateSession(store, "ending", 110, 5);

    // When the "ending" session completes and is removed
    store.removeSession("ending");

    // And new data arrives from the remaining 2 sessions
    store.appendSessionSample("keep-a", { tokens: 420, cost: 0.42, agents: 1, context: 30 });
    store.appendSessionSample("keep-b", { tokens: 310, cost: 0.31, agents: 1, context: 50 });

    // Then the aggregate reflects only the 2 remaining sessions (420 + 310 = 730)
    const aggBuffer = store.getAggregateBuffer("tokens");
    const latestSample = aggBuffer.samples[aggBuffer.samples.length - 1];
    expect(latestSample.tokenRate).toBe(730);
  });

  it("removed session no longer appears in per-session buffer lookups", () => {
    // Given a session that has ended
    const store = createMultiSessionStore();
    populateSession(store, "ended-session", 200, 5);
    store.removeSession("ended-session");

    // When per-session buffer is requested
    const buffer = store.getSessionBuffer("ended-session", "tokens");

    // Then no buffer is returned for the ended session
    expect(buffer).toBeUndefined();
  });
});

// ---------------------------------------------------------------------------
// ERROR/BOUNDARY SCENARIOS: Empty state
// Traces to: US-PMR-01 AC4
// ---------------------------------------------------------------------------

describe("Empty state when no sessions are active", () => {
  it("aggregate buffer has no samples when no sessions exist", () => {
    // Given Raj has no active Claude Code sessions
    const store = createMultiSessionStore();

    // When the aggregate token buffer is retrieved
    const aggBuffer = store.getAggregateBuffer("tokens");

    // Then no samples are available
    expect(aggBuffer.samples).toHaveLength(0);
  });

  it("chart point preparation returns empty array for zero samples", () => {
    // Given no sample data
    const emptySamples: ReadonlyArray<{ timestamp: number; value: number }> = [];

    // When chart points are prepared
    const points = prepareFilledAreaPoints(emptySamples, CHART_DIMENSIONS, 1000);

    // Then no chart points are produced (triggers empty-state display)
    expect(points).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// ERROR/BOUNDARY SCENARIOS: Data pipeline edge cases
// Traces to: US-PMR-01 AC6
// ---------------------------------------------------------------------------

describe("Chart handles maximum buffer size without data corruption", () => {
  it("buffer at capacity evicts oldest while maintaining renderable points", () => {
    // Given a session that has been running long enough to fill the buffer
    const store = createMultiSessionStore();
    store.addSession("long-running");

    // When 70 samples are appended (exceeds DEFAULT_BUFFER_CAPACITY=60)
    for (let i = 0; i < 70; i++) {
      store.appendSessionSample("long-running", {
        tokens: 100 + (i % 50),
        cost: 0.01,
        agents: 1,
        context: 40,
      });
    }

    // Then the buffer has exactly capacity samples (oldest evicted)
    const buffer = store.getSessionBuffer("long-running", "tokens");
    expect(buffer).toBeDefined();
    expect(buffer!.samples.length).toBeLessThanOrEqual(60);
    expect(buffer!.samples.length).toBeGreaterThan(0);

    // And chart points can be rendered from the capped buffer
    const chartSamples = toChartSamples(buffer!.samples);
    const points = prepareFilledAreaPoints(chartSamples, CHART_DIMENSIONS, 200);
    expect(points.length).toBeGreaterThan(0);
    for (const point of points) {
      expect(Number.isFinite(point.x)).toBe(true);
      expect(Number.isFinite(point.y)).toBe(true);
    }
  });
});

describe("Chart renders correctly with single data point", () => {
  it("one sample produces one chart point at a valid position", () => {
    // Given a session with exactly one event
    const store = createMultiSessionStore();
    store.addSession("single-event");
    store.appendSessionSample("single-event", { tokens: 500, cost: 0.5, agents: 1, context: 60 });

    // When chart points are prepared
    const buffer = store.getSessionBuffer("single-event", "tokens")!;
    const chartSamples = toChartSamples(buffer.samples);
    const points = prepareFilledAreaPoints(chartSamples, CHART_DIMENSIONS, 1000);

    // Then exactly 1 point is produced with valid coordinates
    expect(points).toHaveLength(1);
    expect(Number.isFinite(points[0].x)).toBe(true);
    expect(Number.isFinite(points[0].y)).toBe(true);
  });
});

describe("All zero token rates produce flat baseline, not blank chart", () => {
  it("zero-rate samples create points at the bottom of the chart", () => {
    // Given sessions generating zero tokens (idle state)
    const store = createMultiSessionStore();
    populateSession(store, "idle-session", 0, 10);

    // When chart points are prepared
    const buffer = store.getSessionBuffer("idle-session", "tokens")!;
    const chartSamples = toChartSamples(buffer.samples);
    const points = prepareFilledAreaPoints(chartSamples, CHART_DIMENSIONS, 1000);

    // Then all points are at the bottom baseline (chart is not blank)
    expect(points.length).toBe(10);
    const bottomY = CHART_DIMENSIONS.height - CHART_DIMENSIONS.padding;
    for (const point of points) {
      expect(point.y).toBe(bottomY);
    }
  });
});

// ---------------------------------------------------------------------------
// ERROR SCENARIO: Appending to nonexistent session
// ---------------------------------------------------------------------------

describe("Appending data to a session that does not exist is safe", () => {
  it("no crash or data corruption when session ID is unknown", () => {
    // Given a store with no sessions
    const store = createMultiSessionStore();

    // When data is appended to a nonexistent session
    expect(() => {
      store.appendSessionSample("phantom", { tokens: 999, cost: 0.9, agents: 1, context: 100 });
    }).not.toThrow();

    // Then no buffer is created for the phantom session
    expect(store.getSessionBuffer("phantom", "tokens")).toBeUndefined();

    // And the aggregate buffer is unaffected
    expect(store.getAggregateBuffer("tokens").samples).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// PROPERTY-SHAPED SCENARIO
// Traces to: US-PMR-01 "non-empty buffer whenever sessions have events"
// ---------------------------------------------------------------------------

describe("@property: aggregate buffer is non-empty whenever active sessions have events", () => {
  it("for any combination of 1-5 sessions with events, aggregate has samples", () => {
    for (let sessionCount = 1; sessionCount <= 5; sessionCount++) {
      // Given N active sessions each with at least one event
      const store = createMultiSessionStore();
      for (let i = 0; i < sessionCount; i++) {
        store.addSession(`session-${i}`);
        store.appendSessionSample(`session-${i}`, {
          tokens: 100 * (i + 1),
          cost: 0.01 * (i + 1),
          agents: 1,
          context: 20 + i * 10,
        });
      }

      // Then the aggregate token buffer is always non-empty
      const aggBuffer = store.getAggregateBuffer("tokens");
      expect(aggBuffer.samples.length).toBeGreaterThan(0);
    }
  });
});

